css:
.loader {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
  width: 120px;
  height: 20px;
  background:linear-gradient(90deg,color-mix(in srgb, currentColor 25%, transparent) 33%,color-mix(in srgb, currentColor 25%, transparent) 50%,color-mix(in srgb, currentColor 25%, transparent) 66%)var(--loader-secondary-color, #86efac);
  background-size:300% 100%;
  animation: l1 1s infinite linear;
}@keyframes l1 {0% {background-position: right}}
